class ImageProcessingController < ApplicationController
  def process_image
    image = params[:image]
    format = params[:format] || 'jpg'
    width = params[:width].to_i || 800
    height = params[:height].to_i || 600
    `convert #{Rails.root}/public/uploads/#{image} -resize #{width}x#{height} #{Rails.root}/public/uploads/converted_#{SecureRandom.hex}.#{format}`
    render json: { message: 'Image processing completed' }
  end
end